"""Calculator module with basic and advanced operations."""


def _validate_numeric(*args):
    for a in args:
        if not isinstance(a, (int, float)):
            raise TypeError(f"Expected numeric type, got {type(a).__name__}")


def add(a, b):
    _validate_numeric(a, b)
    return a + b


def subtract(a, b):
    _validate_numeric(a, b)
    return a - b


def multiply(a, b):
    _validate_numeric(a, b)
    return a * b


def divide(a, b):
    _validate_numeric(a, b)
    if b == 0:
        raise ValueError("division by zero")
    return a / b
